// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of [http.ServeMux].
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	http.Handler
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/health", wrapper.GetHealth)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects", wrapper.ListProjects)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/v1/projects", wrapper.CreateProject)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}", wrapper.GetProject)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/audit-events", wrapper.ListAuditEvents)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/environments", wrapper.ListEnvironments)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/v1/projects/{slug}/environments", wrapper.CreateEnvironment)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/environments/{envSlug}", wrapper.GetEnvironment)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/flags", wrapper.ListFlags)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/v1/projects/{slug}/flags", wrapper.CreateFlag)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/flags/{key}", wrapper.GetFlag)
	m.HandleFunc(http.MethodPut+" "+options.BaseURL+"/v1/projects/{slug}/flags/{key}", wrapper.PublishFlagVersion)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/v1/projects/{slug}/flags/{key}/evaluate", wrapper.EvaluateFlag)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/v1/projects/{slug}/flags/{key}/evaluate-trace", wrapper.EvaluateFlagWithTrace)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/flags/{key}/versions", wrapper.ListFlagVersions)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/segments", wrapper.ListSegments)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/v1/projects/{slug}/segments", wrapper.CreateSegment)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/segments/{segKey}", wrapper.GetSegment)
	m.HandleFunc(http.MethodPut+" "+options.BaseURL+"/v1/projects/{slug}/segments/{segKey}", wrapper.UpdateSegment)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/snapshots", wrapper.ListSnapshots)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/v1/projects/{slug}/snapshots", wrapper.CompileSnapshot)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/snapshots/latest", wrapper.GetLatestSnapshot)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/v1/projects/{slug}/snapshots/{id}", wrapper.GetSnapshot)

	return m
}

